/**
 * 🛰️ CONFIGURACIÓN MAESTRA DE RED
 * Cambia 'ZT' por 'LAN' o 'TS' para redirigir todo el tráfico de n8n.
 */
const RED_ACTIVA = 'ZT'; 

const networkDictionary = {
  "DEBIAN": {
    "LAN": "10.200.8.197",
    "ZT": "10.147.18.4",
    "TS": "100.123.98.5"
  },
  "SQL": {
    "LAN": "10.200.8.5",
    "ZT": "10.147.18.192",
    "TS": "100.125.8.80"
  },
  "PC_DARIO": {
    "LAN": "10.200.8.114",
    "ZT": "10.147.18.63",
    "TS": "100.126.220.118" // Extraída de synapse_credentials.md (dario-desktop)
  }
};

// Normalización y Fallback
const mode = RED_ACTIVA.toUpperCase();

return {
  network: mode,
  DEBIAN: networkDictionary.DEBIAN[mode] || networkDictionary.DEBIAN.ZT,
  SQL: networkDictionary.SQL[mode] || networkDictionary.SQL.ZT,
  PC_DARIO: networkDictionary.PC_DARIO[mode] || networkDictionary.PC_DARIO.ZT
};
